--
-- Name: calculate_salary(integer, date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_salary(employee_id integer, start_date date, end_date date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    base_salary DECIMAL(10,2);
    worked_days INTEGER;
    total_salary DECIMAL(10,2);
BEGIN
    -- Получаем базовый оклад
    SELECT ставка INTO base_salary FROM Сотрудники WHERE id = employee_id;
    
    -- Считаем количество рабочих дней
    SELECT COUNT(*) INTO worked_days
    FROM График_работы
    WHERE сотрудник_id = employee_id 
    AND дата BETWEEN start_date AND end_date
    AND статус = 'Работал';
    
    -- Расчет зарплаты (оклад / 22 рабочих дня * фактически отработанные дни)
    total_salary := (base_salary / 22) * worked_days;
    
    RETURN total_salary;
END;
$$;


ALTER FUNCTION public.calculate_salary(employee_id integer, start_date date, end_date date) OWNER TO postgres;

--
-- Name: f_check_stock_and_create_missing(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_check_stock_and_create_missing() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    stock_count integer;
    missing_count integer;
    active_missing_id integer;
BEGIN
    SELECT COALESCE("количество", 0)
    INTO stock_count
    FROM "Склад"
    WHERE "товар_id" = NEW."товар_id";

    missing_count := NEW."количество" - stock_count;

    SELECT id
    INTO active_missing_id
    FROM "Недостающие_товары"
    WHERE "заявка_id" = NEW."заявка_id"
      AND "товар_id" = NEW."товар_id"
      AND COALESCE("статус", 'в обработке') <> 'получено'
      AND "недостающее_количество" > 0
      AND COALESCE("активна", true) = true
    ORDER BY id DESC
    LIMIT 1;

    IF missing_count > 0 THEN
        IF active_missing_id IS NOT NULL THEN
            UPDATE "Недостающие_товары"
            SET "необходимое_количество" = NEW."количество",
                "недостающее_количество" = missing_count,
                "статус" = 'в обработке',
                "активна" = true,
                "закрыто_в" = NULL
            WHERE id = active_missing_id;
        ELSE
            INSERT INTO "Недостающие_товары" (
                "заявка_id",
                "товар_id",
                "необходимое_количество",
                "недостающее_количество",
                "статус",
                "активна",
                "создано_в",
                "закрыто_в"
            ) VALUES (
                NEW."заявка_id",
                NEW."товар_id",
                NEW."количество",
                missing_count,
                'в обработке',
                true,
                CURRENT_TIMESTAMP,
                NULL
            );
        END IF;
    ELSE
        IF active_missing_id IS NOT NULL THEN
            UPDATE "Недостающие_товары"
            SET "необходимое_количество" = NEW."количество",
                "недостающее_количество" = 0,
                "статус" = 'получено',
                "активна" = false,
                "закрыто_в" = CURRENT_TIMESTAMP
            WHERE id = active_missing_id;
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_check_stock_and_create_missing() OWNER TO postgres;

