--
-- Name: f_create_purchase_on_missing_items(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_create_purchase_on_missing_items() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    supplier_id INTEGER;
    purchase_id INTEGER;
    item_price DECIMAL(10,2);
BEGIN
    IF NEW."статус" = 'в обработке' AND (TG_OP = 'INSERT' OR OLD."статус" IS DISTINCT FROM NEW."статус") THEN
        SELECT "поставщик_id","цена" INTO supplier_id, item_price
        FROM "Ассортимент_поставщиков"
        WHERE "товар_id" = NEW."товар_id"
        ORDER BY "цена" ASC
        LIMIT 1;

        IF supplier_id IS NOT NULL THEN
            INSERT INTO "Закупки" ("поставщик_id","заявка_id","статус")
            VALUES (supplier_id, NEW."заявка_id", 'заказано')
            RETURNING id INTO purchase_id;

            INSERT INTO "Позиции_закупки" ("закупка_id","товар_id","количество","цена")
            VALUES (purchase_id, NEW."товар_id", COALESCE(NEW."недостающее_количество",0), item_price);

            -- можно также обновить статус/поле в Недостающие_товары если надо
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_create_purchase_on_missing_items() OWNER TO postgres;

--
-- Name: f_create_stock_movement_on_purchase_receipt(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_create_stock_movement_on_purchase_receipt() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW."статус" = 'получено' AND (TG_OP = 'INSERT' OR OLD."статус" IS DISTINCT FROM NEW."статус") THEN
        INSERT INTO "Движения_склада" ("товар_id","тип_операции","количество","закупка_id","комментарий")
        SELECT pz."товар_id", 'приход', pz."количество", NEW."id", 'Поступление по закупке ' || NEW."id"
        FROM "Позиции_закупки" pz
        WHERE pz."закупка_id" = NEW."id";

        IF NEW."заявка_id" IS NOT NULL THEN
            UPDATE "Недостающие_товары"
            SET "статус" = 'получено'
            WHERE "заявка_id" = NEW."заявка_id"
              AND "товар_id" IN (SELECT "товар_id" FROM "Позиции_закупки" WHERE "закупка_id" = NEW."id")
              AND "статус" = 'заказано';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_create_stock_movement_on_purchase_receipt() OWNER TO postgres;

--
-- Name: f_create_stock_movement_on_shipment(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_create_stock_movement_on_shipment() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW."статус" = 'доставлено' AND (TG_OP = 'INSERT' OR OLD."статус" IS DISTINCT FROM NEW."статус") THEN
        INSERT INTO "Движения_склада" ("товар_id","тип_операции","количество","заявка_id","комментарий")
        SELECT pz."товар_id", 'расход', pz."количество", NEW."заявка_id", 'Отгрузка по заявке ' || NEW."заявка_id"
        FROM "Позиции_заявки" pz
        WHERE pz."заявка_id" = NEW."заявка_id";

        UPDATE "Заявки"
        SET "статус" = 'отгружена', "дата_выполнения" = CURRENT_TIMESTAMP
        WHERE id = NEW."заявка_id";
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_create_stock_movement_on_shipment() OWNER TO postgres;

--
-- Name: f_skip_direct_order_warehouse_movements(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_skip_direct_order_warehouse_movements() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    direct_order_exists BOOLEAN := false;
BEGIN
    IF NEW."заявка_id" IS NULL THEN
        RETURN NEW;
    END IF;

    SELECT EXISTS (
        SELECT 1
        FROM public."Заявки"
        WHERE id = NEW."заявка_id"
          AND COALESCE("режим_исполнения", 'warehouse') = 'direct'
    )
    INTO direct_order_exists;

    IF NOT direct_order_exists THEN
        RETURN NEW;
    END IF;

    IF TG_OP = 'INSERT' THEN
        RETURN NULL;
    END IF;

    RETURN OLD;
END;
$$;


ALTER FUNCTION public.f_skip_direct_order_warehouse_movements() OWNER TO postgres;

--
-- Name: f_update_company_balance(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_update_company_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    previous_balance DECIMAL(12,2);
BEGIN
    SELECT "баланс_после" INTO previous_balance
    FROM "Финансы_компании"
    ORDER BY "дата" DESC, id DESC
    LIMIT 1;

    previous_balance := COALESCE(previous_balance, 0);

    IF NEW."тип" = 'поступление' THEN
        NEW."баланс_после" := previous_balance + COALESCE(NEW."сумма",0);
    ELSIF NEW."тип" = 'расход' THEN
        NEW."баланс_после" := previous_balance - COALESCE(NEW."сумма",0);
    ELSE
        NEW."баланс_после" := previous_balance;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_update_company_balance() OWNER TO postgres;

--
-- Name: f_update_order_total(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_update_order_total() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'DELETE' THEN
        UPDATE "Заявки"
        SET "общая_сумма" = COALESCE((
            SELECT SUM("количество" * "цена") FROM "Позиции_заявки" WHERE "заявка_id" = OLD."заявка_id"
        ), 0)
        WHERE id = OLD."заявка_id";
        RETURN OLD;
    ELSE
        UPDATE "Заявки"
        SET "общая_сумма" = COALESCE((
            SELECT SUM("количество" * "цена") FROM "Позиции_заявки" WHERE "заявка_id" = NEW."заявка_id"
        ), 0)
        WHERE id = NEW."заявка_id";
        RETURN NEW;
    END IF;
END;
$$;


