--
-- Name: f_validate_email(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_validate_email() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
BEGIN
    IF NEW."email" IS NOT NULL AND NEW."email" !~* '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$' THEN
        RAISE EXCEPTION 'Некорректный формат email: %', NEW."email";
    END IF;
    RETURN NEW;
END;
$_$;


