--
-- Name: f_validate_order_item_price(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_validate_order_item_price() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    current_price DECIMAL(10,2);
BEGIN
    SELECT "цена_продажи" INTO current_price FROM "Товары" WHERE id = NEW."товар_id";

    IF NEW."цена" IS NULL OR NEW."цена" = 0 THEN
        NEW."цена" := current_price;
    END IF;

    IF current_price IS NOT NULL AND NEW."цена" < current_price * 0.9 THEN
        RAISE EXCEPTION 'Цена продажи не может быть ниже 90%% от базовой цены. Товар: %, Базовая цена: %', NEW."товар_id", current_price;
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_validate_order_item_price() OWNER TO postgres;

--
-- Name: f_validate_work_schedule(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.f_validate_work_schedule() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM public."Сотрудники"
        WHERE id = NEW."сотрудник_id"
          AND "активен" = true
    ) THEN
        RAISE EXCEPTION 'Нельзя добавить график для неактивного сотрудника';
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.f_validate_work_schedule() OWNER TO postgres;

