--
-- Name: get_financial_report(timestamp without time zone, timestamp without time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_financial_report(start_date timestamp without time zone, end_date timestamp without time zone) RETURNS TABLE("период" text, "поступления" numeric, "расходы" numeric, "прибыль" numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        'Отчетный период' as период,
        COALESCE(SUM(CASE WHEN тип = 'поступление' THEN сумма ELSE 0 END), 0) as поступления,
        COALESCE(SUM(CASE WHEN тип = 'расход' THEN сумма ELSE 0 END), 0) as расходы,
        COALESCE(SUM(CASE WHEN тип = 'поступление' THEN сумма ELSE -сумма END), 0) as прибыль
    FROM Финансы_компании
    WHERE дата BETWEEN start_date AND end_date;
END;
$$;


ALTER FUNCTION public.get_financial_report(start_date timestamp without time zone, end_date timestamp without time zone) OWNER TO postgres;

--
-- Name: get_warehouse_status(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_warehouse_status() RETURNS TABLE("товар_id" integer, "название_товара" character varying, "артикул" character varying, "количество_на_складе" integer, "минимальный_остаток" integer, "статус" text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        т.id,
        т.название,
        т.артикул,
        COALESCE(с.количество, 0) as количество_на_складе,
        т.минимальный_остаток,
        CASE 
            WHEN COALESCE(с.количество, 0) <= 0 THEN 'Нет в наличии'
            WHEN COALESCE(с.количество, 0) <= т.минимальный_остаток THEN 'Мало остаток'
            ELSE 'В наличии'
        END as статус
    FROM Товары т
    LEFT JOIN Склад с ON т.id = с.товар_id
    ORDER BY т.категория, т.название;
END;
$$;


ALTER FUNCTION public.get_warehouse_status() OWNER TO postgres;

--
-- Name: sym_largeobject(oid); Type: FUNCTION; Schema: public; Owner: symuser
--

CREATE FUNCTION public.sym_largeobject(objectid oid) RETURNS text
    LANGUAGE plpgsql
    AS $$     DECLARE           encodedBlob text;         encodedBlobPage text;         BEGIN             encodedBlob := '';        FOR encodedBlobPage IN SELECT pg_catalog.encode(data, 'escape')      FROM pg_largeobject WHERE loid = objectId ORDER BY pageno LOOP              encodedBlob := encodedBlob || encodedBlobPage;          END LOOP;       RETURN pg_catalog.encode(pg_catalog.decode(encodedBlob, 'escape'), 'base64');       EXCEPTION WHEN OTHERS THEN        RETURN '';    END             $$;


ALTER FUNCTION public.sym_largeobject(objectid oid) OWNER TO symuser;

