--
-- Name: анализ_клиентов; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."анализ_клиентов" AS
 SELECT "к".id AS "клиент_id",
    "к"."название" AS "клиент",
    "к"."тип",
    count("з".id) AS "количество_заявок",
    COALESCE(sum("з"."общая_сумма"), (0)::numeric) AS "общая_сумма_покупок",
        CASE
            WHEN (count("з".id) > 0) THEN (COALESCE(sum("з"."общая_сумма"), (0)::numeric) / (count("з".id))::numeric)
            ELSE (0)::numeric
        END AS "средний_чек",
    max("з"."дата_создания") AS "последняя_покупка",
    count(DISTINCT date_trunc('month'::text, "з"."дата_создания")) AS "активные_месяцы",
        CASE
            WHEN (count("з".id) >= 10) THEN 'VIP'::text
            WHEN (count("з".id) >= 5) THEN 'Постоянный'::text
            WHEN (count("з".id) >= 1) THEN 'Новый'::text
            ELSE 'Потенциальный'::text
        END AS "категория_клиента"
   FROM (public."Клиенты" "к"
     LEFT JOIN public."Заявки" "з" ON (("к".id = "з"."клиент_id")))
  GROUP BY "к".id, "к"."название", "к"."тип";


ALTER VIEW public."анализ_клиентов" OWNER TO postgres;

--
-- Name: анализ_недостач; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."анализ_недостач" AS
 SELECT "т".id AS "товар_id",
    "т"."название" AS "товар",
    "т"."категория",
    count("нт".id) AS "количество_недостач",
    sum("нт"."недостающее_количество") AS "общее_недостающее_количество",
    avg("нт"."недостающее_количество") AS "средняя_недостача",
    min("нт"."недостающее_количество") AS "минимальная_недостача",
    max("нт"."недостающее_количество") AS "максимальная_недостача",
    ( SELECT "п"."название"
           FROM (public."Ассортимент_поставщиков" "ап"
             JOIN public."Поставщики" "п" ON (("ап"."поставщик_id" = "п".id)))
          WHERE ("ап"."товар_id" = "т".id)
          ORDER BY "ап"."цена"
         LIMIT 1) AS "рекомендуемый_поставщик"
   FROM (public."Товары" "т"
     JOIN public."Недостающие_товары" "нт" ON (("т".id = "нт"."товар_id")))
  GROUP BY "т".id, "т"."название", "т"."категория";


ALTER VIEW public."анализ_недостач" OWNER TO postgres;

--
-- Name: анализ_поставщиков; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."анализ_поставщиков" AS
 SELECT "п".id AS "поставщик_id",
    "п"."название" AS "поставщик",
    "п"."рейтинг",
    count("з".id) AS "количество_закупок",
    COALESCE(sum("з"."общая_сумма"), (0)::numeric) AS "сумма_закупок",
        CASE
            WHEN (count("з".id) > 0) THEN (COALESCE(sum("з"."общая_сумма"), (0)::numeric) / (count("з".id))::numeric)
            ELSE (0)::numeric
        END AS "средний_чек_закупки",
    count("ап"."товар_id") AS "количество_товаров_в_ассортименте",
    min("ап"."срок_поставки") AS "минимальный_срок_поставки",
    max("ап"."срок_поставки") AS "максимальный_срок_поставки"
   FROM ((public."Поставщики" "п"
     LEFT JOIN public."Закупки" "з" ON (("п".id = "з"."поставщик_id")))
     LEFT JOIN public."Ассортимент_поставщиков" "ап" ON (("п".id = "ап"."поставщик_id")))
  GROUP BY "п".id, "п"."название", "п"."рейтинг";


ALTER VIEW public."анализ_поставщиков" OWNER TO postgres;

--
-- Name: движения_склада_детализированные; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."движения_склада_детализированные" AS
 SELECT "дс".id,
    "дс"."дата_операции",
    "т"."название" AS "товар",
    "т"."категория",
    "дс"."тип_операции",
    "дс"."количество",
    "з".id AS "заявка_id",
    "з"."статус" AS "статус_заявки",
    "зк".id AS "закупка_id",
    "зк"."статус" AS "статус_закупки",
    "дс"."комментарий",
    ( SELECT "с"."количество"
           FROM public."Склад" "с"
          WHERE ("с"."товар_id" = "дс"."товар_id")) AS "текущий_остаток"
   FROM (((public."Движения_склада" "дс"
     JOIN public."Товары" "т" ON (("дс"."товар_id" = "т".id)))
     LEFT JOIN public."Заявки" "з" ON (("дс"."заявка_id" = "з".id)))
     LEFT JOIN public."Закупки" "зк" ON (("дс"."закупка_id" = "зк".id)))
  ORDER BY "дс"."дата_операции" DESC;


ALTER VIEW public."движения_склада_детализированные" OWNER TO postgres;

--
-- Name: продажи_по_периодам; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."продажи_по_периодам" AS
 WITH "продажи_по_месяцам" AS (
         SELECT date_trunc('month'::text, "з"."дата_создания") AS "месяц",
            count("з".id) AS "количество_заявок",
            sum("з"."общая_сумма") AS "общая_сумма",
            avg("з"."общая_сумма") AS "средний_чек",
            count(DISTINCT "з"."клиент_id") AS "уникальные_клиенты",
                CASE
                    WHEN (count(DISTINCT "з"."клиент_id") > 0) THEN (sum("з"."общая_сумма") / (count(DISTINCT "з"."клиент_id"))::numeric)
                    ELSE (0)::numeric
                END AS "средний_чек_на_клиента"
           FROM public."Заявки" "з"
          WHERE (("з"."статус")::text <> 'отменена'::text)
          GROUP BY (date_trunc('month'::text, "з"."дата_создания"))
        ), "популярные_товары" AS (
         SELECT date_trunc('month'::text, "з"."дата_создания") AS "месяц",
            "т"."название" AS "товар_название",
            sum("pз"."количество") AS "общее_количество",
            row_number() OVER (PARTITION BY (date_trunc('month'::text, "з"."дата_создания")) ORDER BY (sum("pз"."количество")) DESC) AS "ранг"
           FROM ((public."Заявки" "з"
             JOIN public."Позиции_заявки" "pз" ON (("з".id = "pз"."заявка_id")))
             JOIN public."Товары" "т" ON (("pз"."товар_id" = "т".id)))
          WHERE (("з"."статус")::text <> 'отменена'::text)
          GROUP BY (date_trunc('month'::text, "з"."дата_создания")), "т"."название"
        )
 SELECT "пм"."месяц",
    "пм"."количество_заявок",
    "пм"."общая_сумма",
    "пм"."средний_чек",
    "пм"."уникальные_клиенты",
    "пм"."средний_чек_на_клиента",
    "пт"."товар_название" AS "самый_популярный_товар"
   FROM ("продажи_по_месяцам" "пм"
     LEFT JOIN "популярные_товары" "пт" ON ((("пм"."месяц" = "пт"."месяц") AND ("пт"."ранг" = 1))));


ALTER VIEW public."продажи_по_периодам" OWNER TO postgres;

--
-- Name: статистика_транспортных_компаний; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."статистика_транспортных_компаний" AS
 SELECT "тк".id AS "транспортная_компания_id",
    "тк"."название" AS "транспортная_компания",
    count("о".id) AS "количество_отгрузок",
    avg("о"."стоимость_доставки") AS "средняя_стоимость_доставки",
    sum("о"."стоимость_доставки") AS "общая_стоимость_доставки",
    count(
        CASE
            WHEN (("о"."статус")::text = 'доставлено'::text) THEN 1
            ELSE NULL::integer
        END) AS "успешные_доставки",
    count(
        CASE
            WHEN (("о"."статус")::text = 'отменено'::text) THEN 1
            ELSE NULL::integer
        END) AS "отмененные_доставки",
        CASE
            WHEN (count("о".id) > 0) THEN (((count(
            CASE
                WHEN (("о"."статус")::text = 'доставлено'::text) THEN 1
                ELSE NULL::integer
            END))::numeric * 100.0) / (count("о".id))::numeric)
            ELSE (0)::numeric
        END AS "процент_успешных_доставок",
    avg(
        CASE
            WHEN ((("о"."статус")::text = 'доставлено'::text) AND ("з"."дата_выполнения" IS NOT NULL)) THEN (EXTRACT(epoch FROM ("з"."дата_выполнения" - "о"."дата_отгрузки")) / (86400)::numeric)
            ELSE NULL::numeric
        END) AS "среднее_время_доставки_дни"
   FROM ((public."Транспортные_компании" "тк"
     LEFT JOIN public."Отгрузки" "о" ON (("тк".id = "о"."транспорт_id")))
     LEFT JOIN public."Заявки" "з" ON (("о"."заявка_id" = "з".id)))
  GROUP BY "тк".id, "тк"."название";


ALTER VIEW public."статистика_транспортных_компаний" OWNER TO postgres;

--
-- Name: финансовый_обзор; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."финансовый_обзор" AS
 WITH "месячные_данные" AS (
         SELECT date_trunc('month'::text, "ф"."дата") AS "месяц",
            sum(
                CASE
                    WHEN (("ф"."тип")::text = 'поступление'::text) THEN "ф"."сумма"
                    ELSE (0)::numeric
                END) AS "поступления",
            sum(
                CASE
                    WHEN (("ф"."тип")::text = 'расход'::text) THEN "ф"."сумма"
                    ELSE (0)::numeric
                END) AS "расходы",
            max("ф"."баланс_после") AS "конечный_баланс"
           FROM public."Финансы_компании" "ф"
          GROUP BY (date_trunc('month'::text, "ф"."дата"))
        )
 SELECT "месяц",
    "поступления",
    "расходы",
    ("поступления" - "расходы") AS "прибыль",
        CASE
            WHEN ("поступления" > (0)::numeric) THEN ((("поступления" - "расходы") / "поступления") * (100)::numeric)
            ELSE (0)::numeric
        END AS "рентабельность",
    "конечный_баланс"
   FROM "месячные_данные"
  ORDER BY "месяц" DESC;


ALTER VIEW public."финансовый_обзор" OWNER TO postgres;

--
-- Name: эффективность_сотрудников; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public."эффективность_сотрудников" AS
 SELECT "с".id AS "сотрудник_id",
    "с"."фио",
    "с"."должность",
    count(DISTINCT "з".id) AS "количество_заявок",
    COALESCE(sum("з"."общая_сумма"), (0)::numeric) AS "сумма_продаж",
    count(DISTINCT "гр"."дата") AS "отработано_дней",
    COALESCE(sum("в"."сумма"), (0)::numeric) AS "сумма_выплат",
        CASE
            WHEN (count(DISTINCT "з".id) > 0) THEN (COALESCE(sum("з"."общая_сумма"), (0)::numeric) / (count(DISTINCT "з".id))::numeric)
            ELSE (0)::numeric
        END AS "средний_чек"
   FROM (((public."Сотрудники" "с"
     LEFT JOIN public."Заявки" "з" ON (("с".id = "з"."менеджер_id")))
     LEFT JOIN public."График_работы" "гр" ON ((("с".id = "гр"."сотрудник_id") AND (("гр"."статус")::text = 'Работал'::text))))
     LEFT JOIN public."Выплаты" "в" ON (("с".id = "в"."сотрудник_id")))
  WHERE ("с"."активен" = true)
  GROUP BY "с".id, "с"."фио", "с"."должность";


ALTER VIEW public."эффективность_сотрудников" OWNER TO postgres;

